+struct HealthCheckGuard<'a, R, F>
+where
+    R: Send + 'static,
+    F: AsyncResourceFactory<Resource = R>,
+{
+    pool: &'a GenericPool<R, F>,
+    completed: bool,
+}
+
+impl<R, F> Drop for HealthCheckGuard<'_, R, F>
+where
+    R: Send + 'static,
+    F: AsyncResourceFactory<Resource = R>,
+{
+    fn drop(&mut self) {
+        if !self.completed {
+            self.pool.reject_unhealthy_idle_resource();
+        }
+    }
+}
+
